import jsonimport socketfrom Searcher import screamimport timeHOST = socket.gethostbyname(socket.gethostname())PORT = 8080devices = []server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)server.setblocking(False)server.bind((HOST, PORT))while True:    try:        conn, adr = server.accept()        print("Connected by", adr)        break    except:        scream()        server.listen()        time.sleep(2)def recvall(conn, length):    data = bytearray()    while len(data) < length:        packet = conn.recv(length - len(data))        if not packet:            return None        data.extend(packet)    return bytes(data)def recv_message(conn):    raw_msglen = recvall(conn, 4)    if not raw_msglen:        return None    msglen = int.from_bytes(raw_msglen, byteorder='big')    return recvall(conn, msglen)receives_data = json.loads(recv_message(conn).decode('utf-8'))data = recv_message(conn)with open(receives_data['name'], 'wb') as f:    f.write(data)# print(data)